1	// scans input packet
2	
3	// status_vec key:
4	// assign status_vec = {port_p, pass_ip, pass_ethmac, crc_zero, category};
5	//  bit 0-1  category: 3=UDP, 2=ICMP, 1=ARP, 0=other
6	//  bit 2  CRC32 passed
7	//  bit 3  Destination MAC matched our configuration
8	//  bit 4  valid IP packet of some kind
9	//  bit 5-7  UDP virtual port number, output of CAM
10	
11	// I haven't yet started trying to handle authentication here.
12	// That can wait; we have the architecture ready.
13	
14	// This is a relatively long file, but it helps that it is broken down
15	// into smaller modules:
16	//   scanner   top level, see doc/rtefi.eps
17	//    - arp_patt
18	//    - ip_patt
19	//    - icmp_patt
20	//    - udp_patt
21	// The four submodules have relatively consistent ports and semantics.
22	
23	module scanner (
24		input clk,  // timespec 6.8 ns
25		input [7:0] eth_in,
26		input eth_in_s,
27		input eth_in_e,  // error flag from PHY
28		// PSPEPS didn't do anything with eth_in_e, which is certainly
29		// a mistake, but did work in practice.  Ditto for this version,
30		// and it's proven to be very robust.  Presumably the 32-bit CRC
31		// makes the RX_ER bit effectively redundant?
32		//
33		// New port: async input to allow packet reception
34		// Lets someone turn off the Ethernet subsystem during maintenance,
35		// e.g., changing IP address.
36		input enable_rx,
37		// port to MAC/IP config, single-cycle latency
38		output [3:0] ip_a,
39		input [7:0] ip_d,
40		// port to UDP port number config memory, single-cycle latency
41		output [3:0] pno_a,
42		input [7:0] pno_d,
43		// Access to a single-cycle-latency RAM holding keys and masks,
44		// necessarily also in the Rx clock domain.
45		// output [9:0] key_addr,
46		// input [15:0] key_data,
47		//
48		// Two-bit summary info available to precog
49		// For a kept packet, busy has the full width of odata_s,
50		// but is delayed one cycle.  Non-keep packets can have the busy
51		// line de-asserted as soon as the dropping condition is detected.
52		// When an incoming packet is categorized as causing a response,
53		// the keep line is asserted one cycle before busy falls.
54		// Also see doc/precog_upg.eps
55		output busy,
56		output keep,
57		output [3:0] debug,
58		//
59		// Simple flow of data to the next processing stage (pbuf_writer).
60		// somewhat conforms to AXI-stream-lite, if I adjust the names?
61		output [7:0] odata,
62		output odata_s,
63		output odata_f,
64		output status_valid,
65		output [7:0] status_vec,
66		output [10:0] pack_len
67	);
68	// Configuration
69	parameter handle_arp = 1;
70	parameter handle_icmp = 1;
71	
72	// We need enable_rx in our own clk domain
73	wire enable_rx_r;
74	reg_tech_cdc enable_rx_cdc(.I(enable_rx), .C(clk), .O(enable_rx_r));
75	
76	// Ethernet frame state machine, primarily based on eth_strobe from PHY
77	wire [7:0] eth_octet = eth_in;
78	wire eth_strobe = eth_in_s;
79	// exactly four states, one-hot encoded
80	reg h_idle=1, h_preamble=0, h_data=0, h_drop=0;
81	// The exact start of frame (transition from h_preamble to h_data)
82	// is controlled by a traditional Ethernet synchronization preamble and SFD.
83	// That old-school bit-pattern of 10101010 10101010 10101011
84	// looks like 55 55 d5 when read over the 8-bit GMII port.  See
85	// https://en.wikipedia.org/wiki/Ethernet_frame#Preamble_and_start_frame_delimiter
86	wire drop_packet;
87	reg [3:0] ifg_count=0;  // Inter-frame gap counter
88	wire ifg_inc = ~(&ifg_count[3:2]);  // saturate at 12
89	wire ifg_ok = ifg_count >= 10;  // slightly relaxed from spec of 12,
90	// this configuration guarantees 11 non-data cycles between frames
91	always @(posedge clk) begin
92		if (h_idle | h_preamble) ifg_count <= ifg_count + ifg_inc;
93		else ifg_count <= 0;
94		if (h_idle & eth_strobe) begin
95			h_idle <= 0;
96			if (eth_octet==8'h55 && enable_rx_r) h_preamble <= 1;
97			else h_drop <= 1;
98		end
99		if (h_preamble) begin
100			if (eth_strobe & (eth_octet==8'hd5)) begin
101				h_preamble <= 0;
102				if (ifg_ok) h_data <= 1;
103				else h_drop <= 1;  // IFG too small.
104			end else if (eth_strobe & (eth_octet!=8'h55)) begin
105				h_preamble <= 0; h_drop <= 1;
106			end else if (~eth_strobe) begin
107				h_preamble <= 0; h_idle <= 1;
108			end
109		end
110		if (h_data) begin
111			if (~eth_strobe) begin
112				h_data <= 0; h_idle <= 1;
113			end else if (drop_packet) begin   // poorly tested
114				h_data <= 0; h_drop <= 1;
115			end
116		end
117		if (h_drop & ~eth_strobe) begin
118			h_drop <= 0; h_idle <= 1;
119		end
120	end
121	
122	// Debug helper
123	reg [1:0] debug1_r=0;
124	always @(posedge clk) begin
125		if (h_idle) debug1_r <= 0;
126		if (h_preamble) debug1_r <= 1;
127		if (h_data) debug1_r <= 3;
128		if (h_drop) debug1_r <= 2;
129	end
130	
131	// Synchronization and pipelining step
132	// Squelch data that isn't being considered
133	reg h_data_d1=0, h_data_d2=0, data_first=0;
134	reg [7:0] data_d1=0, data_d2=0;
135	always @(posedge clk) begin
136		h_data_d1 <= h_data;
137		h_data_d2 <= h_data & h_data_d1;  // XXX horrible hack
138		// Why does h_data last one octet past last Ethernet octet in data?
139		data_first <= h_data & ~h_data_d1;
140		data_d1 <= eth_strobe ? eth_octet : 8'b0;
141		data_d2 <= data_d1;
142	end
143	
144	// Unified handling of MAC/IP addresses via external config memory
145	//
146	// Ethernet
147	// Dest    MAC:  octets 0-5    match me (might be FF for broadcast)
148	// Source  MAC:  octets 6-11
149	//
150	// ARP (RFC 826)
151	// Sender  MAC:  octets 22-27
152	// Sender   IP:  octets 28-31
153	// Placeholder:  octets 32-37
154	// Dest     IP:  octets 38-41  match me
155	//
156	// IP (RFC 791)
157	// Source   IP:  octets 26-29
158	// Dest     IP:  octets 30-33  match me
159	//
160	// ICMP (RFC 792)
161	// UDP (RFC 768)
162	//
163	reg [10:0] pack_cnt=0;
164	always @(posedge clk) begin
165		pack_cnt <= h_data ? pack_cnt+1 : 0;
166	end
167	assign drop_packet = pack_cnt >= 1536;
168	assign ip_a = pack_cnt > 36 || pack_cnt < 16 ? pack_cnt[3:0] : pack_cnt[3:0]+8;
169	wire ip_m = ip_d == data_d1;
170	// This pack_cnt decoding is synthesizable as is; we can make it more gate-
171	// efficient later, using synthesis measurements and good regression tests.
172	reg want_c_eth=0, want_c_arp=0, want_c_ip=0;
173	always @(posedge clk) begin
174		want_c_eth <= pack_cnt < 6;
175		want_c_arp <= pack_cnt >= 38 && pack_cnt < 42;
176		want_c_ip  <= pack_cnt >= 30 && pack_cnt < 34;
177	end
178	// Accumulate state
179	wire pz = pack_cnt == 0;
180	reg pass_ethmac=0;  always @(posedge clk) begin if (want_c_eth & ~ip_m) pass_ethmac <= 0; if (pz) pass_ethmac <= 1; end
181	reg pass_arpip=0;   always @(posedge clk) begin if (want_c_arp & ~ip_m) pass_arpip  <= 0; if (pz) pass_arpip  <= 1; end
182	reg pass_ipdst=0;   always @(posedge clk) begin if (want_c_ip  & ~ip_m) pass_ipdst  <= 0; if (pz) pass_ipdst  <= 1; end
183	
184	// Specific protocols; IP is a component of both ICMP and UDP
185	wire [15:0] ip_length, udp_length;
186	
187	// ARP handling is optional, chosen by the handle_arp parameter.
188	wire pass_arp0;
189	generate if (handle_arp) begin : find_arp
190		arp_patt arp_p (.clk(clk), .cnt(pack_cnt), .data(data_d1), .pass(pass_arp0));
191	end else begin : no_find_arp
192		assign pass_arp0 = 0;
193	end endgenerate
194	
195	// ICMP handling is optional, chosen by the handle_icmp parameter.
196	wire pass_icmp0;
197	generate if (handle_icmp) begin : find_icmp
198		icmp_patt icmp_p(.clk(clk), .cnt(pack_cnt), .data(data_d1), .pass(pass_icmp0));
199	end else begin : no_find_icmp
200		assign pass_icmp0 = 0;
201	end endgenerate
202	
203	// IP, UDP, and checksum handling are given, but see note below about UDP checksums.
204	wire pass_ip0;   ip_patt   ip_p  (.clk(clk), .cnt(pack_cnt), .data(data_d1), .pass(pass_ip0), .length(ip_length));
205	wire pass_udp0;  udp_patt  udp_p (.clk(clk), .cnt(pack_cnt), .data(data_d1), .pass(pass_udp0), .length(udp_length));
206	wire pass_sum;   cksum_chk chk_p (.clk(clk), .cnt(pack_cnt), .data(data_d1), .pass(pass_sum), .length(ip_length));
207	
208	// CRC32
209	wire crc_zero;
210	crc8e_guts crc8e(.clk(clk), .gate(h_data_d1), .first(data_first),
211		.d_in(data_d1), .zero(crc_zero));
212	wire final_octet = h_data_d1 & ~h_data;
213	
214	// UDP port number
215	reg udp_port_stb=0;
216	always @(posedge clk) udp_port_stb <= pack_cnt == 36;
217	wire [2:0] port_p0;  wire port_h, port_v;
218	udp_port_cam #(.naw(3)) cam(.clk(clk),
219		.port_s(udp_port_stb), .data(data_d1),
220		.pno_a(pno_a), .pno_d(pno_d),
221		.port_p(port_p0), .port_h(port_h), .port_v(port_v)
222	);
223	
224	// Packet length (doesn't count GMII preamble)
225	reg [10:0] pack_len_r=0;
226	always @(posedge clk) if (h_data) pack_len_r <= pack_cnt;
227	
228	// Weird place for this
229	reg ip_len_check=0, udp_len_check=0;
230	always @(posedge clk) if (h_data) begin
231		ip_len_check <= pack_cnt >= ip_length + 18; // 18 = 14 Ethernet header + 4 CRC
232		udp_len_check <= ip_length >= udp_length + 20; // 20 = IP header length
233	end
234	
235	// One more oddball
236	reg unicast_src_mac=0;
237	always @(posedge clk) begin
238		if (pack_cnt==1) unicast_src_mac <= 1;  // optimistic, needed to make busy flag work
239		if (pack_cnt==7) unicast_src_mac <= ~data_d1[0];
240	end
241	
242	// Summary bits (mostly) don't leak irrelevant state
243	wire pass_arp  = unicast_src_mac & crc_zero & pass_arp0 & pass_arpip;
244	wire pass_ip   = unicast_src_mac & crc_zero & pass_ethmac & pass_ip0 & pass_ipdst & ip_len_check;
245	wire pass_icmp = pass_ip & pass_icmp0 & pass_sum;
246	wire pass_udp  = pass_ip & pass_udp0 & udp_len_check & port_h;
247	wire [1:0] category = pass_udp ? 3 : pass_icmp ? 2 : pass_arp ? 1 : 0;
248	wire [2:0] port_p = pass_udp ? port_p0 : 3'd0;
249	
250	// Summary output
251	assign status_vec = {port_p, pass_ip, pass_ethmac, crc_zero, category};
252	assign status_valid = final_octet;
253	assign pack_len = pack_len_r;
254	
255	// Other summary output
256	wire busy_with_arp = unicast_src_mac & pass_arp0;
257	wire busy_with_udp = unicast_src_mac & pass_ethmac & pass_ip0 & pass_udp0;
258	wire busy_with_icmp = unicast_src_mac & pass_ethmac & pass_ip0 & pass_icmp0;
259	reg busy_r=0, keep_r=0;
260	always @(posedge clk) begin
261		busy_r <= odata_s & (busy_with_arp | busy_with_udp | busy_with_icmp);
262		keep_r <= odata_s & (category != 0);
263	end
264	assign busy = busy_r;
265	assign keep = keep_r;
266	
267	// Debug helper
268	reg [1:0] debug2_r=0;
269	always @(posedge clk) begin
270		if (status_valid) debug2_r <= category;
271	end
272	assign debug = {debug2_r, debug1_r};
273	
274	// Output ports
275	assign odata = data_d2;
276	assign odata_s = h_data_d2;
277	assign odata_f = final_octet;
278	
279	endmodule
280	
281	// New modules to get new name spaces
282	
283	// =====
284	// UDP/ICMP Checksum checker
285	// Calculation structure for UDP and ICMP is about the same, so it
286	// superficially looks like we just need a little stream selection logic
287	// based on the protocol, and then a single one's-complement accumulator
288	// could handle both cases.
289	// This rosy scenario is stymied by UDP's pathological inclusion of
290	// _two_ copies of the UDP length.  At the moment, therefore, this
291	// module doesn't handle UDP.
292	module cksum_chk(
293		input clk,
294		input [10:0] cnt,
295		input [7:0] data,
296		input [15:0] length,  // IP length
297		output pass
298	);
299	
300	wire chksum_zero = cnt == 22;  // or earlier
301	wire icmp_gate = cnt >= 35;
302	// wire udp_gate = cnt >= 23;
303	wire chksum_gate = icmp_gate;
304	
305	// Make sure length is known before using it
306	wire end_of_ip = cnt>32 && cnt == (length+14);
307	
308	// Standard one's-complement checksum
309	wire ones;
310	ones_chksum ck(.clk(clk), .clear(chksum_zero), .gate(chksum_gate),
311		.din(data), .all_ones(ones));
312	
313	// Final state, should find FF FF at end of IP packet
314	reg eof=0, state=0;
315	always @(posedge clk) begin
316		if (chksum_zero) state <= 0;
317		if (end_of_ip) state <= ones;
318		eof <= end_of_ip;
319		if (eof) state <= state & ones;
320	end
321	assign pass = state;
322	
323	endmodule // UDP/ICMP Checksum checker
324	
325	// =====
326	// ARP pattern checker
327	module arp_patt(
328		input clk,
329		input [10:0] cnt,
330		input [7:0] data,
331		output pass
332	);
333	
334	reg [7:0] template=0;
335	always @(posedge clk) case(cnt[3:0])
336		// template starts at 12th byte of Ethernet packet,
337		// after the two MAC addresses.
338		4'd12: template <= 8'h08;
339		4'd13: template <= 8'h06;
340		4'd14: template <= 8'h00;   // ARP Ethernet hardware, octet 1
341		4'd15: template <= 8'h01;   // ARP Ethernet hardware, octet 2
342		4'd00: template <= 8'h08;   // ARP Protocol IP
343		4'd01: template <= 8'h00;   // ARP Protocol IP
344		4'd02: template <= 8'h06;   // ARP protocol address length
345		4'd03: template <= 8'h04;   // ARP protocol address length
346		4'd04: template <= 8'h00;   // ARP protocol operation
347		4'd05: template <= 8'h01;   // ARP protocol operation (request)
348		default: template <= 8'h00;
349	endcase
350	
351	reg want=0, pass_r=0;
352	wire match = data == template;
353	always @(posedge clk) begin
354		want <= cnt >= 12 && cnt < 22;
355		if (cnt == 0) pass_r <= 1;
356		if (want & ~match) pass_r <= 0;
357	end
358	assign pass = pass_r;
359	
360	endmodule  // ARP pattern checker
361	
362	// =====
363	// IP pattern checker
364	module ip_patt(
365		input clk,
366		input [10:0] cnt,
367		input [7:0] data,
368		output pass,
369		output [15:0] length
370	);
371	
372	reg [7:0] template=0;
373	always @(posedge clk) case(cnt[4:0])
374		// template starts at 12th byte of Ethernet packet,
375		// after the two MAC addresses.
376		5'd12: template <= 8'h08;  // Bytes 12 and 13 are Ethertype IPv4
377		5'd13: template <= 8'h00;  // https://en.wikipedia.org/wiki/Ethertype
378	
379		// Start of IPv4 header [https://en.wikipedia.org/wiki/IPv4#Header]
380		5'd14: template <= 8'h45;  // Vers (4 for ipv4) / IHL (> 5 is a weird case)
381		// 15  ignore  TOS (later changed to DSCP and ECN)
382		// 16  ignore  length msb
383		// 17  ignore  length lsb
384		// 18  ignore  identification msb
385		// 19  ignore  identification lsb
386		5'd20: template <= 8'h00;  // Flags/Fragment
387		5'd21: template <= 8'h00;
388		// 22  ignore  TTL (but see below)
389		// 23  ignore  Protocol
390		// 24-33  header checksum, source address, destination address
391		default: template <= 8'h00;
392	endcase
393	
394	// Packet has expired when TTL hits zero
395	reg ttl_flag=0;
396	wire zero_ttl = ttl_flag & ~(|data);
397	
398	reg want=0, mask_df_bit=0, pass_r=0;
399	wire [7:0] df_mask = {1'b1, ~mask_df_bit, 6'h3f};
400	wire match = (data&df_mask) == template;
401	always @(posedge clk) begin
402		want <= cnt >= 12 && cnt < 15 || cnt >= 20 && cnt < 22;
403		mask_df_bit <= cnt == 20;
404		ttl_flag <= cnt == 22;
405		if (cnt == 0) pass_r <= 1;
406		if (want & ~match) pass_r <= 0;
407		if (zero_ttl) pass_r <= 0;
408	end
409	
410	// IP packet total length
411	// Quoting RFC 791, Total Length is the length of the datagram,
412	// measured in octets, including internet header and data.
413	reg [7:0] data_d=0;
414	reg [15:0] length_r=0;
415	always @(posedge clk) begin
416		data_d <= data;
417		if (cnt==18) length_r <= {data_d, data};
418	end
419	assign length = length_r;
420	
421	// IP header checksum
422	reg out_chksum_gate=0, out_chksum_zero=0;
423	always @(posedge clk) begin
424		out_chksum_gate <= cnt >= 14 && cnt < 34;
425		out_chksum_zero <= cnt == 0;
426	end
427	wire chksum_all_ones;
428	ones_chksum ck(.clk(clk), .clear(out_chksum_zero), .gate(out_chksum_gate),
429		.din(data), .all_ones(chksum_all_ones));
430	reg chksum_all_ones_d=0;
431	reg chksum_fail=0;
432	always @(posedge clk) begin
433		chksum_all_ones_d <= chksum_all_ones;
434		if (cnt==0) chksum_fail <= 0;
435		if (cnt==35) chksum_fail <= ~chksum_all_ones | ~chksum_all_ones_d;
436	end
437	assign pass = pass_r & ~chksum_fail;
438	
439	endmodule  // IP header
440	
441	// =====
442	// ICMP pattern checker
443	// For ICMP checksum see module cksum_chk
444	module icmp_patt(
445		input clk,
446		input [10:0] cnt,
447		input [7:0] data,
448		output pass
449	);
450	
451	reg [7:0] template=0;
452	always @(posedge clk) case(cnt[2:0])
453		// Ethernet/IP header is not in our scope
454		// template starts at 23rd byte of Ethernet packet,
455		// after the two MAC addresses.
456		3'd7: template <= 8'h01;  // cnt==23, Proto (ICMP)
457		3'd2: template <= 8'h08;  // cnt==34, ICMP echo request
458		3'd3: template <= 8'h00;  // cnt==35, ICMP code
459		default: template <= 8'h00;
460	endcase
461	
462	reg want=0, pass_r=0;
463	wire match = data == template;
464	always @(posedge clk) begin
465		want <= cnt == 23 || cnt==34 || cnt==35;
466		if (cnt == 0) pass_r <= 1;
467		if (want & ~match) pass_r <= 0;
468	end
469	assign pass = pass_r;
470	
471	endmodule  // ICMP pattern checker
472	
473	// =====
474	// UDP pattern checker
475	module udp_patt(
476		input clk,
477		input [10:0] cnt,
478		input [7:0] data,
479		output pass,
480		output [15:0] length
481	);
482	
483	// Degenerate form of template ROM
484	// Moving this template and comparison to ip_patt would save 2 LUTs.
485	wire [7:0] template = 8'h11;  // cnt==23, Proto (UDP)
486	
487	// Reject packets from source port number < 1024,
488	// as they come from "trusted" sources.
489	// This is part of the strategy to resist echo loops.
490	wire reject_low = cnt==35 & ~|data[7:2];
491	
492	// Reject packets to destination port number 0
493	reg pzero_d=0, pzero_d1=0, pzero_t=0;
494	always @(posedge clk) begin
495		pzero_d <= data == 8'h00;
496		pzero_d1 <= pzero_d;
497		pzero_t <= cnt == 36;
498	end
499	wire discard_port0 = pzero_t & pzero_d & pzero_d1;
500	
501	reg want=0, pass_r=0;
502	wire match = data == template;
503	always @(posedge clk) begin
504		want <= cnt == 23;
505		if (cnt == 0) pass_r <= 1;
506		if (want & ~match) pass_r <= 0;
507		if (reject_low) pass_r <= 0;
508		if (discard_port0) pass_r <= 0;
509	end
510	assign pass = pass_r;
511	
512	// UDP packet length
513	// Length is the length in octets of this user datagram including [UDP]
514	// header and the data.
515	reg [7:0] data_d=0;
516	reg [15:0] length_r=0;
517	always @(posedge clk) begin
518		data_d <= data;
519		if (cnt==40) length_r <= {data_d, data};
520	end
521	assign length = length_r;
522	
523	// XXX We don't yet compute the UDP checksum.
524	// That may not be a practical problem.
525	
526	endmodule  // UDP pattern checker
527

