1	// Mechanism to reprogram boot flash
2	module spi_flash(
3		input clk,
4		// client interface with RTEFI, see doc/clients.eps
5		input [10:0] len_c,
6		input [7:0] idata,
7		input raw_l,
8		input raw_s,
9		output [7:0] odata,
10		// 4-wire to e.g., Winbond W25X16
11		output spi_clk,
12		output spi_cs,
13		output spi_mosi,
14		input spi_miso,
15		output busy   // only intended for simulation
16	);
17	
18	parameter n_lat = 8;  // latency of client pipeline
19	
20	// Try really hard to be non-fancy here, just the obvious way of
21	// gatewaying the previously functioning spi_flash_engine into
22	// the RTEFI scheme.
23	
24	// Longer term it would be nice if this could be re-written to
25	// allow more resource sharing, say between Rx and Tx buffers,
26	// and code sharing with other buffered clients, like the SPI
27	// slave gateway to a microcontroller, as was done in PSPEPS.
28	
29	// This module cries out to be a customer of an authentication
30	// mechanism, whenever that becomes available.
31	
32	parameter aw=9;  // nominal/minimal 512 x 8
33	reg [7:0] rx_mem[0:(1<<aw)-1];
34	reg [7:0] tx_mem[0:(1<<aw)-1];
35	
36	reg pack_read_ready=0;
37	reg [8:0] rx_packet_len;
38	wire pack_read_strobe;
39	reg [7:0] pack_data_rx=0;
40	
41	wire pack_read_done;
42	wire pack_write;
43	wire pack_write_ack=pack_read_ready;
44	wire pack_write_strobe;
45	wire [7:0] pack_data_tx;
46	
47	spi_flash_engine engine(
48		.clk(clk),
49		.spi_clk(spi_clk),
50		.spi_cs(spi_cs),
51		.spi_mosi(spi_mosi),
52		.spi_miso(spi_miso),
53		//
54		.pack_read_ready(pack_read_ready),
55		.input_packet_len(rx_packet_len),
56		.pack_read_strobe(pack_read_strobe),
57		.pack_data_in(pack_data_rx),
58		.pack_read_done(pack_read_done),
59		//
60		.pack_write(pack_write),
61		.pack_write_ack(pack_write_ack),
62		.pack_write_strobe(pack_write_strobe),
63		.pack_data_out(pack_data_tx)
64	);
65	
66	// Adapt the RTEFI control lines into what we need;
67	// shared between Rx writer and Tx reader.
68	reg [1:0] raw_sr=0;
69	reg [aw-1:0] eth_point=0;
70	always @(posedge clk) begin
71		raw_sr <= {raw_sr[0:0], raw_s};
72		eth_point <= raw_sr[1] ? eth_point+1 : 0;
73	end
74	
75	// Logic for writing Rx memory
76	// Note the decoding of the first byte as a packet-global op-code:
77	//  0x52   write buffer
78	// The write command will fail if the buffer is not empty, and that
79	// failure  gets reported in the status message, below, right?
80	reg rx_for_us=0, write_pack_flag=0;
81	wire rx_mem_write = raw_s & raw_sr[1] & write_pack_flag;
82	wire pre_write_pack_flag = rx_for_us & idata[0];
83	always @(posedge clk) begin
84		if (raw_s & ~raw_sr[0]) rx_for_us <= (idata == 8'h52) && ~pack_read_ready;
85		if (raw_sr[0] & ~raw_sr[1]) write_pack_flag <= pre_write_pack_flag;
86		if (rx_mem_write) rx_mem[eth_point] <= idata;
87		if (raw_sr[0] & ~raw_s & write_pack_flag) pack_read_ready <= 1;
88		if (raw_sr[0] & ~raw_s & write_pack_flag) rx_packet_len <= eth_point;
89		if (pack_read_done) pack_read_ready <= 0;
90	end
91	
92	// Logic for reading Rx memory
93	reg [aw-1:0] rx_rpoint=0;
94	always @(posedge clk) begin
95		if (pack_read_done) rx_rpoint <= 0;
96		if (pack_read_strobe & pack_read_ready) rx_rpoint <= rx_rpoint+1;
97		pack_data_rx <= rx_mem[rx_rpoint];
98	end
99	
100	// Logic for writing Tx memory
101	reg [aw-1:0] tx_wpoint=0;
102	always @(posedge clk) begin
103		if (pack_write_strobe) begin
104			tx_mem[tx_wpoint] <= pack_data_tx;
105			tx_wpoint <= tx_wpoint+1;
106		end
107		if (~pack_write) tx_wpoint <= 0;
108	end
109	
110	// Logic for reading Tx memory
111	// len_c counts down to 9, but we need something that counts up from 0
112	wire [7:0] tx_status = {pre_write_pack_flag, ~pack_read_ready};
113	reg [7:0] tx_rdata=0, odata1=0;
114	always @(posedge clk) begin
115		tx_rdata <= tx_mem[eth_point];
116		odata1 <= raw_sr[1] ? tx_rdata : raw_sr[0] ? tx_status : 8'h51;
117	end
118	
119	// Internal-only for viewing in simulation
120	reg [7:0] status_report;
121	wire status_capture_tick = ~raw_sr[1] & raw_sr[0];
122	always @(posedge clk) if (status_capture_tick) status_report <= tx_status;
123	
124	// output packet:
125	//   message type
126	//   status byte
127	//   buffer memory
128	// how about buffer length, i.e., tx_wpoint before it got erased?
129	
130	// choose to pipeline output
131	reg_delay #(.len(n_lat-1), .dw(8)) align(.clk(clk), .gate(1'b1), .reset(1'b0),
132		.din(odata1), .dout(odata));
133	
134	assign busy = pack_read_ready;
135	
136	endmodule
