1	// Transitional/transformational module
2	// Uses the rearranged input packet and meta-information
3	// to create output packet, still sans CRC32.
4	module xformer(
5		input clk,  // timespec 6.8 ns
6		input [5:0] pc,
7		input [1:0] category,
8		input [2:0] udp_sel,
9		input [7:0] idata,
10		input eth_strobe_short,
11		input eth_strobe_long,
12		// As documented in doc/clients.eps
13		output [10:0] len_c,
14		// Don't bother with a data output port to the clients,
15		// since what they need is exactly a copy of idata above.
16		// 7 of these strobes for the 7 possible clients
17		output [6:0] raw_l,
18		output [6:0] raw_s,
19		// mass input from 7 possible clients
20		input [7*8-1:0] mux_data_in,
21		//
22		output [7:0] odata,
23		output ostrobe_s,
24		output ostrobe_l
25	);
26	
27	// Configuration
28	parameter n_lat=2;
29	parameter handle_icmp = 1;
30	
31	wire icmp = (category == 2) & handle_icmp;
32	wire udp = category == 3;
33	
34	// ICMP Echo Checksum (see RFC 792 p. 13)
35	// For causality reasons, can only be hacked based on
36	// assuming the input checksum was valid.
37	// This was the approach taken by Du in icmp_rx.v.
38	wire [7:0] d_out2;
39	// Desired pc cycle is 41 in the frame of tx_ip_table.txt,
40	// but we've accumulated two cycles of pipeline delay.
41	reg icmp_kick=0; always @(posedge clk) icmp_kick <= icmp & (pc==42);
42	wire [7:0] odata0;
43	// Always instantiate this; it turns into a simple pass-through
44	// (two cycles delayed) when not kicked.
45	hack_icmp_cksum hack_icmp_cksum(.clk(clk),
46		.kick(icmp_kick), .idat(idata), .odat(odata0));
47	
48	// Delay strobe to match 2-cycle delay in hack_icmp_chksum; refactor?
49	reg o_strobe1=0, o_strobe2=0;
50	reg l_strobe1=0, l_strobe2=0;
51	always @(posedge clk) begin
52		o_strobe1 <= eth_strobe_short;
53		o_strobe2 <= o_strobe1;
54		l_strobe1 <= eth_strobe_long;
55		l_strobe2 <= l_strobe1 && category != 0;
56	end
57	
58	// Timing
59	// It's OK to pass-through the UDP checksum when udp_sel==0, because
60	// nothing has changed from Rx packet except the order of IP addresses
61	// and port numbers, and the checksum process is not sensitive to the
62	// order of 16-bit words.  For all other UDP packets, we have to disable
63	// the checksum by replacing it with zero.  See below.
64	reg pc_at_checksum=0;
65	reg use_zero=0, use_copy=0;
66	always @(posedge clk) begin
67		use_copy <= ~udp || pc < 48 || udp_sel == 0;
68		pc_at_checksum <= pc == 46 || pc == 47;
69		use_zero <= udp && (udp_sel != 0) && pc_at_checksum;
70	end
71	
72	// UDP length down-counter
73	reg [10:0] pdata_count=0;
74	reg [3:0] len_stb=0;
75	wire len_soon = pc==43 && udp;
76	reg pdata_down=0;
77	always @(posedge clk) begin
78		len_stb <= {len_stb[2:0], len_soon};
79		if (len_stb[0]) pdata_count[10:8] <= idata[2:0];
80		if (len_stb[1]) pdata_count[7:0] <= idata;
81		// a zero-length UDP packet must never assert data-valid
82		if (len_stb[3] && pdata_count > 8) pdata_down <= 1;
83		if (pdata_down) pdata_count <= pdata_count - 1;
84		if (pdata_count == 9) pdata_down <= 0;
85	end
86	
87	// Signals documented in doc/clients.eps
88	// Fan out the strobes based on udp_sel
89	wire [7:0] mask = 1 << udp_sel;
90	assign len_c = pdata_count;
91	assign raw_l = mask[7:1] & {7{eth_strobe_long}};
92	assign raw_s = mask[7:1] & {7{pdata_down}};
93	
94	// Pipeline alignment
95	// Names are horrid
96	wire [11:0] pipe_in = {o_strobe2, l_strobe2, use_zero, use_copy, odata0};
97	wire use_zero1, use_copy1;  wire [7:0] odata1;
98	reg_delay #(.len(n_lat-2), .dw(12)) pipe(.clk(clk), .gate(1'b1), .reset(1'b0),
99		.din(pipe_in),
100		.dout({ostrobe_s, ostrobe_l, use_zero1, use_copy1, odata1}));
101	
102	// Multiplexer
103	// Suppress UDP checksum for causality reasons; if there's a client
104	// that wants to fake it, we would need to give it an option to set
105	// the checksum to some non-zero (but still constant) value here.
106	reg [7:0] odatax;
107	wire [8*8-1:0] mux_data_in2 = {mux_data_in, odata1};
108	always @(*) begin
109		if (use_zero1) odatax = 0;  // UDP checksum
110		else if (use_copy1) odatax = odata1;
111		else odatax = mux_data_in2[8*udp_sel +: 8];
112	end
113	assign odata = odatax;
114	
115	endmodule
